Hi @davisking,

This is basically syntactic sugar. Instead of writing a function with a `for` loop that does the conversion, it can be done directly by implementing this type.

My end goal was to introduce a multi-threaded queue for batch sampling without replacement on the C++ side and then exposing it to Python as well. The queue would encapsulate the mechanism used [here](https://github.com/davisking/dlib/blob/master/examples/dnn_metric_learning_on_images_ex.cpp) (for example).

I wanted the queue to return normalised pixel values to avoid processing on the Python side while images are being read from the queue.

Since the batch will then typically be copied to the GPU, I wanted to return the batch as a Numpy array of the form (batch_size, height, width, 3).

To that end, I have the following generic code:
```
template <
    typename pixel_type
    >
    void assert_is_image_array(const std::vector<matrix<pixel_type>>& imgs) {
        // We expect every image to be the same size
        size_t rows_from_images = -1;
        size_t cols_from_images = -1;

        for(auto image : imgs) {
            if(rows_from_images == -1)
                rows_from_images = num_rows(image);
            if(cols_from_images == -1) {
                cols_from_images = num_columns(image);
            }
            size_t current_image_rows = num_rows(image);
            size_t current_image_cols = num_columns(image);
            if(current_image_rows != rows_from_images || current_image_cols != cols_from_images) {
                throw dlib::error("Cannot convert from std::vector<matrix<pixel_type>> to Numpy as images in vector have different sizes");
            }
        }
    }

template <
    typename pixel_type
    >
class numpy_images : public py::array_t<typename pixel_traits<pixel_type>::basic_pixel_type>
{
    /*!
        REQUIREMENTS ON pixel_type
            - is a dlib pixel type, this just means that dlib::pixel_traits<pixel_type>
                is defined.
        WHAT THIS OBJECT REPRESENTS
            This is collection of N images of the same size which can be created/assigned from 
            an std::vector containing matrix<pixel_type> objects. This object helps return a 
            Numpy array of the shape (N, image_rows, image_cols, 3)
    !*/
public:

    numpy_images() = default;

    numpy_images(std::vector<matrix<pixel_type>>&& rhs) {
        *this = convert_to_numpy(std::move(rhs));
    }

    numpy_images& operator= (
        std::vector<matrix<pixel_type>>&& rhs
    )
    {
        *this = convert_to_numpy(std::move(rhs));
        return *this;
    }

    numpy_images& operator= (
        const py::array_t<typename pixel_traits<pixel_type>::basic_pixel_type>& rhs
    )
    {
        py::array_t<typename pixel_traits<pixel_type>::basic_pixel_type>::operator=(rhs);
        return *this;
    }

private:
    static py::array_t<typename pixel_traits<pixel_type>::basic_pixel_type> convert_to_numpy(std::vector<matrix<pixel_type>>&& imgs)
    {
        assert_is_image_array(imgs);

        using basic_pixel_type = typename pixel_traits<pixel_type>::basic_pixel_type;
        const size_t dtype_size = sizeof(basic_pixel_type);
        const auto batch = static_cast<const size_t>(imgs.size());
        const auto rows = batch != 0 ? static_cast<const size_t>(num_rows(imgs[0])) : 0;
        const auto cols = batch != 0 ? static_cast<const size_t>(num_columns(imgs[0])) : 0;
        const size_t channels = pixel_traits<pixel_type>::num;
        const size_t block_size = dtype_size * batch * rows * cols * channels;
        const size_t image_ptr_counter_step = rows * cols * channels;
        const size_t image_size = dtype_size * rows * cols * channels;
        size_t image_ptr_counter = 0;
        basic_pixel_type* memory = (basic_pixel_type*) malloc(block_size);

        int image_num = 1;
        for(matrix<pixel_type> img : imgs) {
            std::unique_ptr<pixel_type[]> arr_ptr = img.steal_memory();
            basic_pixel_type* arr = (basic_pixel_type *) arr_ptr.release();
            basic_pixel_type* destination = memory + image_ptr_counter;
            memcpy (destination, arr, image_size);
            delete[] arr;
            image_ptr_counter += image_ptr_counter_step;
        }

        return pybind11::template array_t<basic_pixel_type>(
            {batch, rows, cols, channels},                                                  // shape
            {
                dtype_size * rows * cols * channels, 
                dtype_size * cols * channels, 
                dtype_size * channels, 
                dtype_size
            },                                                                              // strides
            memory,                                                                         // pointer
            pybind11::capsule{ memory, [](void *arr_p) { delete[] reinterpret_cast<basic_pixel_type*>(arr_p); } }
        );
    }
};
```

As you can see, introducing the rgb_normalized_pixel, the above code would work without any special handling for normalisation.

